import { useState, useEffect, ComponentType } from 'react';

// HOC that adds loading behavior to any component
function withLoading<P extends object>(
  WrappedComponent: ComponentType<P>,
  fetchData: () => Promise<Partial<P>>
) {
  return function WithLoadingComponent(props: Omit<P, keyof Awaited<ReturnType<typeof fetchData>>>) {
    const [data, setData] = useState<Partial<P> | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
      fetchData()
        .then(setData)
        .finally(() => setLoading(false));
    }, []);

    if (loading) return <p>Loading...</p>;
    if (!data) return <p>Failed to load data.</p>;

    return <WrappedComponent {...(props as P)} {...data} />;
  };
}

// Usage
interface UserListProps {
  users: User[];
}

function UserList({ users }: UserListProps) {
  return (
    <ul>
      {users.map((u) => <li key={u.id}>{u.name}</li>)}
    </ul>
  );
}

const UserListWithLoading = withLoading(UserList, () =>
  fetch('/api/users').then((r) => r.json()).then((users) => ({ users }))
);

// Now <UserListWithLoading /> automatically fetches and shows loading state
